def calculate_average(nums: list[float]) -> float:
    """
    Calculates the average of a list of numbers.
    Returns 0.0 for an empty list to avoid ZeroDivisionError.
    """
    if not nums:
        return 0.0
    return sum(nums) / len(nums)

